LAYER_OLD = 'addLayer({id:"country-labels",type:"symbol",source:"country-labels",\n    layout:{"text-field":["get","name"],"text-font":["Noto Sans Regular"],\n      "text-size":["get","size"],"text-max-width":7,"text-padding":2,\n      "text-rotate":["get","rot"],"text-rotation-alignment":"map","text-pitch-alignment":"map",\n      "symbol-sort-key":["*",-1,["get","size"]],\n      "symbol-placement":"point","text-allow-overlap":false,"visibility":"none"},\n    paint:{"text-color":"#3a3226","text-halo-color":"rgba(255,255,255,0.55)","text-halo-width":1.1}});'
LAYER_NEW = 'addLayer({id:"country-labels",type:"symbol",source:"country-labels",\n    filter:[">=",["zoom"],["get","minZoom"]],\n    layout:{"text-field":["get","name"],"text-font":["Noto Sans Regular"],\n      "text-size":["get","size"],"text-max-width":7,"text-padding":2,\n      "text-rotate":["get","rot"],"text-rotation-alignment":"map","text-pitch-alignment":"map",\n      "symbol-sort-key":["*",-1,["get","size"]],\n      "symbol-placement":"point","text-allow-overlap":false,"visibility":"none"},\n    paint:{"text-color":"#3a3226","text-halo-color":"rgba(255,255,255,0.55)","text-halo-width":1.1}});'

import re
m = re.search(r"const COUNTRY_LABELS=(\{.*?\});", text)
if not m:
    print("  [ ANCHOR-NOT-FOUND] COUNTRY_LABELS constant")
    sys.exit(1)
if m.group(1) == NEW_LABELS:
    print("  [already-applied] COUNTRY_LABELS constant (with minZoom)")
else:
    text = text[:m.start(1)] + NEW_LABELS + text[m.end(1):]
    print("  [        patched] COUNTRY_LABELS constant (with minZoom)")

if LAYER_NEW in text:
    print("  [already-applied] zoom filter on country-labels layer")
elif LAYER_OLD in text:
    text = text.replace(LAYER_OLD, LAYER_NEW, 1)
    print("  [        patched] zoom filter on country-labels layer")
else:
    print("  [ ANCHOR-NOT-FOUND] country-labels layer block")
    open(OUT, "w", encoding="utf-8").write(text)
    sys.exit(1)

open(OUT, "w", encoding="utf-8").write(text)
print("OK: labels now hide below their own comfortable-fit zoom")
